// src/app/api/tenant/categories/route.ts
import { NextRequest } from 'next/server'
import { prisma } from '@/lib/prisma'
import { requireAuth, getTenantId, successResponse, errorResponse } from '@/lib/api'

const TA = ['TENANT_ADMIN', 'SUPER_ADMIN']
const MAX_DEPTH = 5

// ── Walk up the parentId chain and return depth (1 = root) ───
async function getCategoryDepth(categoryId: string, tenantId: string): Promise<number> {
  let depth = 1
  let currentId: string | null = categoryId
  while (currentId) {
    const cat: { parentId: string | null } | null = await prisma.category.findFirst({
      where: { id: currentId, tenantId },
      select: { parentId: true },
    })
    if (!cat || !cat.parentId) break
    currentId = cat.parentId
    depth++
  }
  return depth
}

// ── Build a nested tree from flat list ────────────────────────
function buildTree(cats: any[]): any[] {
  const map: Record<string, any> = {}
  const roots: any[] = []
  cats.forEach(c => { map[c.id] = { ...c, children: [] } })
  cats.forEach(c => {
    if (c.parentId && map[c.parentId]) {
      map[c.parentId].children.push(map[c.id])
    } else {
      roots.push(map[c.id])
    }
  })
  return roots
}

// GET /api/tenant/categories  — returns flat + nested tree
export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth()
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const { searchParams } = new URL(req.url)
  const flat = searchParams.get('flat') === 'true'

  const cats = await prisma.category.findMany({
    where: { tenantId },
    orderBy: [{ sortOrder: 'asc' }, { name: 'asc' }],
    include: {
      _count: { select: { tickets: true, agentPerms: true } },
    },
  })

  if (flat) return successResponse(cats)
  return successResponse({ tree: buildTree(cats), flat: cats })
}

// POST /api/tenant/categories — create category or sub-category (up to 5 levels)
export async function POST(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const body = await req.json()
  const { name, parentId, department, description, color, icon, sortOrder, type, dropdownOptions } = body

  if (!name?.trim()) return errorResponse('name is required', 400)

  // Validate type value
  const catType: string = type ?? 'NORMAL'
  if (!['NORMAL', 'DROPDOWN', 'TEXT_FIELD'].includes(catType)) {
    return errorResponse('type must be NORMAL, DROPDOWN, or TEXT_FIELD', 400)
  }

  // Validate DROPDOWN requires at least one option
  let optionsJson: string | null = null
  if (catType === 'DROPDOWN') {
    const opts: string[] = Array.isArray(dropdownOptions) ? dropdownOptions.filter((o: any) => typeof o === 'string' && o.trim()) : []
    if (opts.length === 0) return errorResponse('DROPDOWN categories require at least one option', 400)
    optionsJson = JSON.stringify(opts.map((o: string) => o.trim()))
  }

  if (parentId) {
    const parent = await prisma.category.findFirst({ where: { id: parentId, tenantId } })
    if (!parent) return errorResponse('Parent category not found', 404)

    // Parent cannot have a non-NORMAL type (typed categories are leaf nodes)
    if (parent.type !== 'NORMAL') {
      return errorResponse('Cannot add sub-categories to a typed (Dropdown/Text Field) category', 400)
    }

    // Check that adding a child here does not exceed MAX_DEPTH
    const parentDepth = await getCategoryDepth(parentId, tenantId)
    if (parentDepth >= MAX_DEPTH) {
      return errorResponse(`Maximum category depth is ${MAX_DEPTH} levels`, 400)
    }
  }

  // A root category with a non-NORMAL type cannot have children later — that's enforced at add-child time, not here

  const cat = await prisma.category.create({
    data: {
      tenantId,
      parentId:       parentId   || null,
      department:     parentId ? null : (department || null),
      name:           name.trim(),
      description:    description || null,
      type:           catType as any,
      dropdownOptions: optionsJson,
      color:          color      || '#2563EB',
      icon:           icon       || null,
      sortOrder:      sortOrder  ?? 0,
    },
  })

  return successResponse(cat, 201)
}

// PATCH /api/tenant/categories — update category
export async function PATCH(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const body = await req.json()
  const { id, name, description, color, icon, isActive, sortOrder, type, dropdownOptions } = body

  if (!id) return errorResponse('id required', 400)

  const existing = await prisma.category.findFirst({ where: { id, tenantId } })
  if (!existing) return errorResponse('Category not found', 404)

  // If changing type to non-NORMAL, cannot have children
  if (type && type !== 'NORMAL' && type !== existing.type) {
    const childCount = await prisma.category.count({ where: { parentId: id, tenantId } })
    if (childCount > 0) {
      return errorResponse('Cannot change type to Dropdown/Text Field — this category has sub-categories. Remove them first.', 409)
    }
  }

  let optionsJson: string | null | undefined = undefined
  if (type === 'DROPDOWN' || (type === undefined && existing.type === 'DROPDOWN')) {
    if (dropdownOptions !== undefined) {
      const opts: string[] = Array.isArray(dropdownOptions) ? dropdownOptions.filter((o: any) => typeof o === 'string' && o.trim()) : []
      if (opts.length === 0) return errorResponse('DROPDOWN categories require at least one option', 400)
      optionsJson = JSON.stringify(opts.map((o: string) => o.trim()))
    }
  } else if (type === 'NORMAL' || type === 'TEXT_FIELD') {
    optionsJson = null  // clear options when switching away from DROPDOWN
  }

  const cat = await prisma.category.update({
    where: { id },
    data: {
      ...(name        !== undefined ? { name: name.trim() }   : {}),
      ...(description !== undefined ? { description }          : {}),
      ...(color       !== undefined ? { color }                : {}),
      ...(icon        !== undefined ? { icon }                 : {}),
      ...(isActive    !== undefined ? { isActive }             : {}),
      ...(sortOrder   !== undefined ? { sortOrder }            : {}),
      ...(type        !== undefined ? { type: type as any }    : {}),
      ...(optionsJson !== undefined ? { dropdownOptions: optionsJson } : {}),
    },
  })

  return successResponse(cat)
}

// DELETE /api/tenant/categories?id=xxx
export async function DELETE(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const { searchParams } = new URL(req.url)
  const id = searchParams.get('id')
  if (!id) return errorResponse('id required', 400)

  const cat = await prisma.category.findFirst({
    where: { id, tenantId },
    include: {
      children: true,
      _count: { select: { tickets: true } },
    },
  })
  if (!cat) return errorResponse('Category not found', 404)

  if (cat._count.tickets > 0) {
    return errorResponse(`Cannot delete — ${cat._count.tickets} ticket(s) use this category. Reassign them first.`, 409)
  }
  if (cat.children.length > 0) {
    return errorResponse(`Cannot delete — this category has ${cat.children.length} sub-categor${cat.children.length > 1 ? 'ies' : 'y'}. Delete them first.`, 409)
  }

  await prisma.category.delete({ where: { id } })
  return successResponse({ deleted: true })
}
